<?php namespace App\Repositories\Hr;use App\Repositories\BaseRepository;use App\Models\Hr\Designation;use Illuminate\Database\Eloquent\Collection;class DesignationRepository extends BaseRepository{    public function __construct(Designation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Designation    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?Designation    {        return $this->query()->where('code', $code)->first();    }    public function getByDepartment(int $departmentId): Collection    {        return $this->findByField('department_id', $departmentId);    }    public function getActiveDesignations(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByRank(string $rank): Collection    {        return $this->findByField('rank', $rank);    }    public function searchDesignations(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function countEmployeesByDesignation(): Collection    {        return $this->query()->withCount('employees')->get();    }    public function getDesignationHierarchy(int $departmentId): Collection    {        return $this->query()->where('department_id', $departmentId)->orderBy('rank', 'asc')->get();    }}